/* ============================================================
   T-CMD — K4 PDF Generator  (SKV 2104 Section D)
   ============================================================
   Generates a PDF that is an exact visual replica of the
   official Skatteverket K4 form (SKV 2104) by:
     1. Loading the real k4-empty.pdf as a base64 template.
     2. Using pdf-lib to copy each template page into a new doc.
     3. Overlaying text at the exact field coordinates extracted
        from the official form via pdfplumber (y=0 at bottom,
        all values in PDF points, A4 = 595.28 × 841.89 pt).

   This matches what Koinly / Divly / Skatteverket's own e-service
   do internally: generate a *static* PDF that looks identical to
   the form, rather than trying to fill the XFA form directly.

   Usage:
     const buf = await K4PdfFiller.generate(k4Report, userInfo);
     // buf is an ArrayBuffer — wrap in Blob and trigger download.

   k4Report shape (from TaxEngine.generateK4Report):
     { k4Rows, totalGains, totalLosses, year }
   k4Rows item:
     { sym, displayName, side:'gain'|'loss', qty, proc, cost, gain, loss }
   userInfo:
     { name, pnr, year }
   ============================================================ */

window.K4PdfFiller = (() => {

  // ── Template (base64-encoded k4-empty.pdf, SKV 2104) ──────
  // Generated with: python3 -c "import base64,pathlib; print(base64.b64encode(pathlib.Path('k4-empty.pdf').read_bytes()).decode())"
  // This is the official 2-page Skatteverket K4 blank form.
  const K4_TEMPLATE_B64 = '';

  // ── Page geometry (A4 in PDF points) ─────────────────────
  const PAGE_W = 595.28;
  const PAGE_H = 841.89;
  const ROWS_PER_PAGE = 7;

  // ── Coordinate helpers ────────────────────────────────────
  // pdf-lib uses y=0 at BOTTOM.  pdfplumber reports y=0 at TOP.
  // textY: returns the text baseline y-coordinate that visually
  //   centres a given font size inside a [plumbTop, plumbBottom] box.
  function textY(plumbTop, plumbBottom, fontSize) {
    const midTop = (plumbTop + plumbBottom) / 2.0;
    return PAGE_H - midTop - fontSize / 3.0;   // slight baseline nudge, same as Python
  }

  function rowTextY(rowTop, fontSize) {
    return textY(rowTop, rowTop + 24, fontSize); // all data rows are 24 pt tall
  }

  // ── Section D column x-boundaries (PDF points) ───────────
  // Source: pdfplumber extraction from k4-empty.pdf
  const COL = {
    antal:    { x0:  53.72, x1: 118.52 },  // Antal/Belopp     — right-align
    beteckn:  { x0: 118.52, x1: 212.12 },  // Beteckning        — left-align
    pris:     { x0: 212.12, x1: 298.52 },  // Försäljningspris  — right-align
    omkostad: { x0: 298.52, x1: 384.92 },  // Omkostnadsbelopp  — right-align
    vinst:    { x0: 384.92, x1: 471.32 },  // Vinst             — right-align
    forlust:  { x0: 471.32, x1: 557.72 },  // Förlust           — right-align
  };

  // Row top positions (pdfplumber coords, page 2 = Section D sheet)
  const ROW_TOPS = [462.04, 486.04, 510.04, 534.04, 558.04, 582.04, 606.04];

  // Summa row (directly below the 7 data rows)
  const SUMMA = {
    pris:     { x0: 212.12, x1: 298.52, top: 630.05, bot: 666.16 },
    omkostad: { x0: 298.52, x1: 384.92, top: 630.05, bot: 666.16 },
    vinst:    { x0: 384.92, x1: 471.32, top: 630.05, bot: 666.16 },
    forlust:  { x0: 471.32, x1: 557.72, top: 630.05, bot: 666.16 },
  };

  // Ruta 7.5 (total gains) and 8.4 (70% deductible losses)
  const RUTA_75 = { x0: 39.32, x1: 406.52, top: 678.18, bot: 714.06 };
  const RUTA_84 = { x0: 39.32, x1: 492.92, top: 726.10, bot: 762.06 };

  // Page 1 (first K4 sheet only) header boxes
  const P1 = {
    inkomstar: { x0: 298.52, x1: 428.12, top: 78.01,  bot: 102.09 },
    datum:     { x0: 428.12, x1: 557.72, top: 78.01,  bot: 102.01 },
    numrering: { x0: 428.12, x1: 557.72, top: 114.01, bot: 138.01 },
    namn:      { x0:  39.32, x1: 428.12, top: 162.01, bot: 186.01 },
    personnr:  { x0: 428.12, x1: 557.72, top: 162.01, bot: 186.01 },
  };

  // Page 2 header (Personnummer top-right of every Section D sheet)
  const P2_PERSONNR = { x0: 428.12, x1: 557.72, top: 30.00, bot: 54.00 };

  // ── WinAnsi sanitizer ────────────────────────────────────
  // pdf-lib's standard fonts (Helvetica, etc.) use WinAnsi encoding which only
  // covers U+0000–U+00FF.  Characters above that range throw:
  //   "WinAnsi cannot encode '◎' (0x25ce)"
  // This happens whenever a token symbol or display name contains emoji or
  // Unicode symbols (◎, ●, ★, →, …).  Strip/transliterate them here so the
  // entire K4 export is never blocked by a single exotic token name.
  function sanitizePdf(value) {
    if (value === null || value === undefined) return '';
    const s = String(value);
    if (!/[^\u0000-\u00FF]/.test(s)) return s; // fast path
    return s.replace(/[^\u0000-\u00FF]/g, ch => {
      const SUBS = {
        '\u25CE': 'o', '\u25CB': 'o', '\u25CF': '*', '\u25C9': 'o',
        '\u2B55': 'o', '\u2022': '-', '\u2023': '-',
        '\u2192': '->', '\u2190': '<-', '\u2194': '<->',
        '\u21D2': '=>', '\u21D0': '<=',
        '\u2248': '~', '\u2260': '!=', '\u221E': 'inf',
        '\u20BF': 'BTC', '\u20AC': 'EUR',
        '\u2019': "'", '\u2018': "'", '\u201C': '"', '\u201D': '"',
        '\u2013': '-',  '\u2014': '-',  '\u2026': '...',
        '\u2605': '*', '\u2606': '*',
        '\u00D7': 'x', '\u00F7': '/',
      };
      return SUBS[ch] !== undefined ? SUBS[ch] : '?';
    });
  }

  // ── Text formatting ───────────────────────────────────────
  function fmtSEK(val) {
    if (!val) return '';
    const n = Math.round(parseFloat(val) || 0);
    return n === 0 ? '' : String(n);
  }

  function fmtQty(val) {
    if (val == null || val === 0 || val === '') return '';
    // Show compact number; replace decimal point with comma for Swedish locale
    const n = parseFloat(val);
    if (isNaN(n)) return String(val);
    // Up to 6 sig figs, strip trailing zeros
    return parseFloat(n.toPrecision(6)).toString().replace('.', ',');
  }

  // ── Main generator ────────────────────────────────────────
  async function generate(k4Report, userInfo) {
    if (typeof PDFLib === 'undefined') {
      throw new Error('pdf-lib not loaded. Add <script src="https://unpkg.com/pdf-lib@1.17.1/dist/pdf-lib.min.js"> to index.html.');
    }
    const { PDFDocument, StandardFonts, rgb } = PDFLib;
    const black = rgb(0, 0, 0);

    const { k4Rows = [], totalGains = 0, totalLosses = 0, year } = k4Report;
    const name   = (userInfo.name  || '').trim();
    const pnr    = (userInfo.pnr   || '').trim();
    const txYear = String(year || userInfo.year || new Date().getFullYear() - 1);
    const today  = new Date().toLocaleDateString('sv-SE');

    // ── Load official form template ───────────────────────
    const templateBytes = Uint8Array.from(atob(K4_TEMPLATE_B64), c => c.charCodeAt(0));
    const srcDoc  = await PDFDocument.load(templateBytes);
    const destDoc = await PDFDocument.create();

    // Embed Helvetica (covers all Latin/Swedish characters)
    const font     = await destDoc.embedFont(StandardFonts.Helvetica);
    const fontBold = await destDoc.embedFont(StandardFonts.HelveticaBold);

    // ── Helpers ───────────────────────────────────────────
    // sanitizePdf() is defined at module scope (above fmtSEK) so it can be shared
    // with generateAccountantReport() too.  All draw helpers call it to strip
    // any codepoint > U+00FF before passing text to pdf-lib's WinAnsi font.

    function drawLeft(page, text, box, fontSize, opts = {}) {
      if (!text && text !== 0) return;
      page.drawText(sanitizePdf(text), {
        x:    box.x0 + 3,
        y:    textY(box.top, box.bot, fontSize),
        size: fontSize,
        font: opts.bold ? fontBold : font,
        color: opts.color || black,
      });
    }

    function drawCenter(page, text, box, fontSize, opts = {}) {
      if (!text && text !== 0) return;
      const s   = sanitizePdf(text);
      const w   = font.widthOfTextAtSize(s, fontSize);
      const cx  = (box.x0 + box.x1) / 2;
      page.drawText(s, {
        x:    cx - w / 2,
        y:    textY(box.top, box.bot, fontSize),
        size: fontSize,
        font: opts.bold ? fontBold : font,
        color: opts.color || black,
      });
    }

    function drawRight(page, text, box, fontSize, opts = {}) {
      if (!text && text !== 0) return;
      const s = sanitizePdf(text);
      const w = font.widthOfTextAtSize(s, fontSize);
      page.drawText(s, {
        x:    box.x1 - w - 3,
        y:    textY(box.top, box.bot, fontSize),
        size: fontSize,
        font: opts.bold ? fontBold : font,
        color: opts.color || black,
      });
    }

    function drawRightXY(page, text, rightX, y, fontSize, opts = {}) {
      if (!text && text !== 0) return;
      const s = sanitizePdf(text);
      const w = font.widthOfTextAtSize(s, fontSize);
      page.drawText(s, {
        x:    rightX - w - 3,
        y,
        size: fontSize,
        font: opts.bold ? fontBold : font,
        color: opts.color || black,
      });
    }

    // ── Chunk K4 rows into pages of 7 ────────────────────
    const chunks = [];
    for (let i = 0; i < Math.max(1, k4Rows.length); i += ROWS_PER_PAGE) {
      chunks.push(k4Rows.slice(i, i + ROWS_PER_PAGE));
    }
    const totalSheets = chunks.length;

    // Cross-page grand totals
    const grandGain = Math.round(totalGains);
    const grandLoss = Math.round(totalLosses);

    // ── Build pages ───────────────────────────────────────
    for (let sheetIdx = 0; sheetIdx < totalSheets; sheetIdx++) {
      const rows    = chunks[sheetIdx];
      const isFirst = sheetIdx === 0;
      const isLast  = sheetIdx === totalSheets - 1;

      // ── Page 1 (template page index 0) — only for first K4 sheet ──
      if (isFirst) {
        const [p1] = await destDoc.copyPages(srcDoc, [0]);

        // Inkomstår — centred in box
        drawCenter(p1, txYear, P1.inkomstar, 11, { bold: true });

        // Datum då blanketten fylls i
        drawLeft(p1, today, P1.datum, 9);

        // Blankettnummer (only shown when multiple sheets)
        if (totalSheets > 1) {
          drawCenter(p1, `${sheetIdx + 1}`, P1.numrering, 9);
        }

        // Namn
        drawLeft(p1, name || '—', P1.namn, 9);

        // Personnummer
        drawLeft(p1, pnr || '—', P1.personnr, 9);

        destDoc.addPage(p1);
      }

      // ── Page 2 (template page index 1) — Section D ──────────
      const [p2] = await destDoc.copyPages(srcDoc, [1]);

      // Personnummer header (top-right of every sheet)
      drawLeft(p2, pnr || '—', P2_PERSONNR, 9);

      // ── Data rows ────────────────────────────────────────
      let pageGain = 0, pageLoss = 0, pageProc = 0, pageCost = 0;

      for (let ri = 0; ri < Math.min(rows.length, ROWS_PER_PAGE); ri++) {
        const row  = rows[ri];
        const rTop = ROW_TOPS[ri];
        const ry   = rowTextY(rTop, 8);

        const gain = Math.round(row.gain || 0);
        const loss = Math.round(row.loss || 0);
        const proc = Math.round(row.proc || 0);
        const cost = Math.round(row.cost || 0);
        pageGain += gain;
        pageLoss += loss;
        pageProc += proc;
        pageCost += cost;

        // Antal/Belopp — right-align
        drawRightXY(p2, fmtQty(row.qty), COL.antal.x1, ry, 8);

        // Beteckning — left-align, max ~25 chars; sanitize to strip non-WinAnsi glyphs
        const label = sanitizePdf(String(row.displayName || row.sym || '').substring(0, 25));
        p2.drawText(label, { x: COL.beteckn.x0 + 2, y: ry, size: 8, font, color: black });

        // Försäljningspris — right-align
        drawRightXY(p2, fmtSEK(proc), COL.pris.x1, ry, 8);

        // Omkostnadsbelopp — right-align
        drawRightXY(p2, fmtSEK(cost), COL.omkostad.x1, ry, 8);

        // Vinst OR Förlust — never both on the same row
        if (row.side === 'gain' && gain > 0) {
          drawRightXY(p2, fmtSEK(gain), COL.vinst.x1, ry, 8);
        } else if (row.side === 'loss' && loss > 0) {
          drawRightXY(p2, fmtSEK(loss), COL.forlust.x1, ry, 8);
        }
      }

      // ── Summa row (page subtotals) ────────────────────────
      const sy = textY(SUMMA.vinst.top, SUMMA.vinst.bot, 9);
      drawRight(p2, fmtSEK(pageProc), SUMMA.pris,     8);
      drawRight(p2, fmtSEK(pageCost), SUMMA.omkostad, 8);
      if (pageGain > 0) drawRight(p2, fmtSEK(pageGain), SUMMA.vinst,   9, { bold: true });
      if (pageLoss > 0) drawRight(p2, fmtSEK(pageLoss), SUMMA.forlust, 9, { bold: true });

      // ── Ruta 7.5 and 8.4 — last sheet only ───────────────
      if (isLast) {
        if (grandGain > 0) {
          drawRight(p2, fmtSEK(grandGain), RUTA_75, 11, { bold: true });
        }
        if (grandLoss > 0) {
          const deductible = Math.round(grandLoss * 0.70);
          drawRight(p2, fmtSEK(deductible), RUTA_84, 11, { bold: true });
        }
      }

      destDoc.addPage(p2);
    }

    // ── Serialize ─────────────────────────────────────────
    const pdfBytes = await destDoc.save();
    return pdfBytes.buffer;
  }

  // ── Accountant detail report ──────────────────────────────
  // Generates a supplementary multi-page PDF with every disposal
  // row, cost basis calculation, and wallet source — for accountants.
  async function generateAccountantReport(taxResult, userInfo, allTxns) {
    if (typeof PDFLib === 'undefined') throw new Error('pdf-lib not loaded');
    const { PDFDocument, StandardFonts, rgb } = PDFLib;

    const { disposals = [], year } = taxResult || {};
    const name   = sanitizePdf((userInfo?.name  || '').trim());
    const pnr    = sanitizePdf((userInfo?.pnr   || '').trim());
    const txYear = String(year || userInfo?.year || '');

    const doc   = await PDFDocument.create();
    const font  = await doc.embedFont(StandardFonts.Helvetica);
    const bold  = await doc.embedFont(StandardFonts.HelveticaBold);
    const black = rgb(0, 0, 0);
    const grey  = rgb(0.4, 0.4, 0.4);
    const blue  = rgb(0.18, 0.24, 0.49);

    const PW = 595.28, PH = 841.89;
    const ML = 40, MR = PW - 40;

    let page, y;
    const ROWS_PER_PAGE_REPORT = 22;

    function newPage() {
      page = doc.addPage([PW, PH]);
      y = PH - 50;
      // Header
      page.drawRectangle({ x: 0, y: PH - 32, width: PW, height: 32, color: blue });
      page.drawText('Detaljerad skatterapport — Kryptovalutor', {
        x: ML, y: PH - 22, size: 11, font: bold, color: rgb(1,1,1),
      });
      page.drawText(`${name}  ·  ${pnr}  ·  Inkomstår ${txYear}`, {
        x: ML, y: PH - 35, size: 8, font, color: rgb(0.8,0.85,1),
      });
    }

    function checkSpace(needed = 14) {
      if (y < 55 + needed) newPage();
    }

    newPage();

    // ── Summary box ─────────────────────────────────────────
    const totalGain  = disposals.reduce((s,d) => s + Math.max(0, d.gainLossSEK||0), 0);
    const totalLoss  = disposals.reduce((s,d) => s + Math.max(0, -(d.gainLossSEK||0)), 0);
    const deductible = Math.round(totalLoss * 0.70);

    page.drawRectangle({ x: ML, y: y-48, width: MR-ML, height: 48,
      borderColor: blue, borderWidth: 0.5, color: rgb(0.95,0.96,0.99) });
    page.drawText('Sammanfattning', { x: ML+8, y: y-14, size: 10, font: bold, color: blue });
    page.drawText(`Totala försäljningar:  ${disposals.length}  poster`, { x: ML+8, y: y-26, size: 8, font, color: black });
    page.drawText(`Summa vinst (Ruta 7.5):  ${Math.round(totalGain).toLocaleString('sv-SE')} kr`, { x: ML+8, y: y-36, size: 9, font: bold, color: rgb(0,0.45,0.2) });
    page.drawText(`Summa förlust (avdragsgill 70%, Ruta 8.4):  ${deductible.toLocaleString('sv-SE')} kr`, { x: ML+180, y: y-36, size: 9, font: bold, color: rgb(0.7,0.1,0.1) });
    y -= 60;

    // ── Column headers ────────────────────────────────────────
    function drawTableHeader() {
      checkSpace(20);
      page.drawRectangle({ x: ML, y: y-13, width: MR-ML, height: 13, color: rgb(0.88,0.9,0.95) });
      const headers = [
        ['Datum',        ML+2  ],
        ['Tillgång',     ML+68 ],
        ['Antal',        ML+160],
        ['Försäljning',  ML+210],
        ['Omkostnad',    ML+268],
        ['Vinst',        ML+326],
        ['Förlust',      ML+374],
        ['Metod',        ML+422],
        ['Konto',        ML+475],
      ];
      for (const [label, x] of headers) {
        page.drawText(label, { x, y: y-10, size: 6.5, font: bold, color: blue });
      }
      y -= 14;
    }

    drawTableHeader();
    let rowCount = 0;

    for (const d of disposals) {
      checkSpace(12);
      if (rowCount > 0 && rowCount % ROWS_PER_PAGE_REPORT === 0) {
        drawTableHeader();
      }

      const isGain = (d.gainLossSEK || 0) >= 0;
      const gain   = isGain  ? Math.round(d.gainLossSEK || 0) : 0;
      const loss   = !isGain ? Math.round(Math.abs(d.gainLossSEK || 0)) : 0;

      // Row background (alternating)
      if (rowCount % 2 === 0) {
        page.drawRectangle({ x: ML, y: y-10, width: MR-ML, height: 10, color: rgb(0.97,0.97,0.99) });
      }

      const rowData = [
        [sanitizePdf((d.date||'').slice(0,10)),                                    ML+2  ],
        [sanitizePdf(String(d.assetSymbol||'').substring(0,14)),                   ML+68 ],
        [String(parseFloat((d.amountSold||0).toPrecision(5))),                     ML+160],
        [Math.round(d.proceedsSEK||0).toLocaleString('sv-SE'),                     ML+210],
        [Math.round(d.costBasisSEK||0).toLocaleString('sv-SE'),                    ML+268],
        [gain > 0 ? gain.toLocaleString('sv-SE') : '',                             ML+326],
        [loss > 0 ? loss.toLocaleString('sv-SE') : '',                             ML+374],
        ['Genomsnitt',                                                              ML+422],
        [sanitizePdf(String(d.accountLabel || d.accountId || '').substring(0,14)), ML+475],
      ];

      for (const [val, x] of rowData) {
        if (val) page.drawText(val, { x, y: y-8, size: 7, font, color: black });
      }

      y -= 11;
      rowCount++;
    }

    // ── Final totals ──────────────────────────────────────────
    checkSpace(40);
    y -= 10;
    page.drawLine({ start:{x:ML,y}, end:{x:MR,y}, thickness:0.5, color:blue });
    y -= 14;
    page.drawText(`Summa vinst: ${Math.round(totalGain).toLocaleString('sv-SE')} kr`, {
      x: ML, y, size: 9, font: bold, color: rgb(0,0.45,0.2) });
    page.drawText(`Summa förlust (brutto): ${Math.round(totalLoss).toLocaleString('sv-SE')} kr`, {
      x: ML+160, y, size: 9, font: bold, color: rgb(0.7,0.1,0.1) });
    y -= 12;
    page.drawText(`Avdragsgill förlust (70%): ${deductible.toLocaleString('sv-SE')} kr — för ifyllnad av Ruta 8.4`, {
      x: ML, y, size: 8, font, color: grey });
    y -= 12;
    page.drawText('Beräknat enligt genomsnittsmetoden (genomsnittsmetoden, IL 44:7). Belopp i hela kronor (SEK).',
      { x: ML, y, size: 7, font, color: grey });

    const pdfBytes = await doc.save();
    return pdfBytes.buffer;
  }

  return { generate, generateAccountantReport };

})();
